/**
 * ENTSO-E Retry + Backoff
 * - Handles HTTP errors
 * - Handles empty / invalid XML
 * - Downgrades D+1 → D on first retry
 */

const sc = msg.statusCode;

// detect empty or invalid ENTSO-E payload
const isEmptyEntsoe =
  sc === 200 &&
  (
    typeof msg.payload !== 'string' ||
    !msg.payload.includes('<Publication_MarketDocument')
  );

// retry conditions
if (sc === 429 || sc >= 500 || isEmptyEntsoe) {
  msg._retries = (msg._retries ?? 0) + 1;

  // downgrade D+1 → D on first retry
  if (msg._retries >= 1 && msg._retryMode === 'D+1') {
    msg._retryMode = 'D';
  }

  if (msg._retries > 3) {
    node.warn('ENTSO-E retry limit exceeded');
    return [null, msg]; // let controller fallback
  }

  const delay = 1000 * Math.pow(2, msg._retries);
  node.warn(
    isEmptyEntsoe
      ? 'ENTSO-E empty response → retry'
      : `ENTSO-E retry ${msg._retries}, backoff ${delay}ms`
  );

  // LOOP BACK
  return [msg, null];
}

// success path
return [null, msg];

