/**
 * CZ Spot Price Controller
 * v2.6.0
 *
 * MAJOR:
 * - Device-agnostic price intelligence
 * - Primary + secondary charging windows
 * - price.windows canonical output
 * - Tesla logic fully removed
 * 
 * v2.6.1
 * - splitted "Window Charging Hours" -> Primaty/Secondary Charging Hours
 */

// ======================================================
// VERSION
// ======================================================
const VERSION = '2.6.1';

// ======================================================
// DEBUG
// ======================================================
const DEBUG = flow.get('debug_controller') === true;

function debug(msg) {
  if (!DEBUG) return null;
  return { topic: 'DEBUG', payload: msg };
}

// ======================================================
// CONFIG
// ======================================================
const CFG = {
  source: flow.get('price_data_source') ?? 'ENTSOE_A44',
  windowHoursPrimary: Number(flow.get('window_hours_primary') ?? 4),
  windowHoursSecondary: Number(flow.get('window_hours_secondary') ?? 2),
  desiredSoc: Number(flow.get('desired_soc') ?? 70),
  maxAvgPrice: Number(flow.get('max_avg_price_eur_mwh') ?? 150)
};

// ======================================================
// SOURCE VALIDATION
// ======================================================
if (CFG.source === 'OTE_CHART') {
  if (!msg.payload?.data?.dataLine) throw 'PAYLOAD_SOURCE_MISMATCH_OTE';
  if (Array.isArray(msg.payload.data.dataLine) &&
      msg.payload.data.dataLine.length === 0)
    throw 'OTE_EMPTY_DATASET';
}

if (CFG.source === 'ENTSOE_A44' && !msg.payload?.TimeSeries)
  throw 'PAYLOAD_SOURCE_MISMATCH_ENTSOE';

if (msg.price_source !== CFG.source)
  throw `SOURCE_SWITCH_MISMATCH ${msg.price_source} → ${CFG.source}`;

// ======================================================
// TIME HELPERS
// ======================================================
function toLocalIso(date) {
  const tz = -date.getTimezoneOffset();
  const s = tz >= 0 ? '+' : '-';
  const p = n => String(Math.abs(n)).padStart(2, '0');
  return date.toISOString().replace('Z', `${s}${p(tz/60)}:${p(tz%60)}`);
}

// ======================================================
// FALLBACK (Victron only)
// ======================================================
function buildFallback(reason) {
  const h = Number(flow.get('fallback_start_hour') ?? 1);
  const w = Number(flow.get('fallback_window_hours') ?? 2);
  const soc = Number(flow.get('fallback_soc') ?? 80);

  return [
    {
      topic: 'victron.schedule',
      payload: {
        action: 'set_scheduler',
        schedule: {
          index: 0,
          enabled: true,
          day: 7,
          start_minute: h * 60,
          duration_minute: w * 60,
          soc_setpoint: soc,
          note: 'FALLBACK'
        }
      }
    },
    null,
    null,
    {
      topic: 'controller.status',
      payload: { ok: false, fallback: true, reason, version: VERSION }
    },
    null,
    null,
    debug({ fallback: true, reason })
  ];
}

// ======================================================
// PARSERS
// ======================================================
function parseEntsoeA44(doc) {
  const root = doc?.[Object.keys(doc)[0]];
  const pts = root?.TimeSeries?.[0]?.Period?.[0]?.Point;
  if (!Array.isArray(pts)) throw 'A44_NO_POINTS';

  return pts.map(p => ({
    hour: Number(p.position[0]) - 1,
    price: Number(p['price.amount'][0])
  }));
}

function parseOteChart(doc) {
  const lines = doc?.data?.dataLine;
  if (!Array.isArray(lines)) throw 'OTE_NO_DATALINE';

  const line = lines.find(l =>
    l.title === '60min price reference (EUR/MWh)'
  );
  if (!line?.point || line.point.length !== 96)
    throw 'OTE_INVALID_POINTS';

  const out = [];
  for (let h = 0; h < 24; h++) {
    const p = Number(line.point[h * 4].y);
    if (!Number.isFinite(p)) throw 'OTE_PRICE_INVALID';
    out.push({ hour: h, price: p });
  }
  return out;
}

// ======================================================
// WINDOW FINDER
// ======================================================
function findCheapestWindowInRange(hourly, startMin, startMax, windowHours) {
  let best = null;

  for (let start = startMin; start <= startMax; start++) {
    const end = start + windowHours;
    if (end > 24) continue;

    const slice = hourly.filter(
      h => h.hour >= start && h.hour < end
    );

    if (slice.length !== windowHours) continue;

    const avg = slice.reduce((a,b)=>a+b.price,0) / slice.length;
    const max = Math.max(...slice.map(h=>h.price));

    if (!best || avg < best.avg) {
      best = { start, end, avg, max };
    }
  }

  return best;
}

// ======================================================
// CACHE
// ======================================================
const CACHE_VERSION = 'v2_6_0';
const sig = CFG.source === 'OTE_CHART' ? 'ote' : 'entsoe';
const cacheKey = `prices_${sig}_${msg.delivery_day}_${CACHE_VERSION}`;

let hourly = flow.get(cacheKey);
if (!hourly) {
  try {
    hourly = CFG.source === 'OTE_CHART'
      ? parseOteChart(msg.payload)
      : parseEntsoeA44(msg.payload);
    flow.set(cacheKey, hourly);
  } catch (e) {
    return buildFallback(e);
  }
}

// ======================================================
// MAIN LOGIC
// ======================================================
const winPrimary = findCheapestWindowInRange(
  hourly,
  0,
  23 - CFG.windowHoursPrimary,
  CFG.windowHoursPrimary
);

if (!winPrimary) throw 'NO_PRIMARY_WINDOW';

const winSecondary = findCheapestWindowInRange(
  hourly,
  10,
  17,
  CFG.windowHoursSecondary
);

if (winPrimary.avg > CFG.maxAvgPrice)
  return buildFallback('PRICE_TOO_HIGH');

// ======================================================
// OUTPUTS
// ======================================================
const victronSchedule1Msg = {
  topic:'victron.schedule',
  payload:{ action:'set_scheduler', schedule:{
    enabled:true,
    day:7,
    start_minute: winPrimary.start * 60,
    duration_minute: CFG.windowHoursPrimary * 60,
    soc_setpoint: CFG.desiredSoc
  }}
};

const victronSchedule2Msg = winSecondary ? {
  topic:'victron.schedule',
  payload:{ action:'set_scheduler', schedule:{
    enabled:true,
    day:7,
    start_minute: winSecondary.start * 60,
    duration_minute: CFG.windowHoursSecondary * 60,
    soc_setpoint: CFG.desiredSoc
  }}
} : null;

const priceWindows = {
  topic:'price.windows',
  payload:{
    version: VERSION,
    source: CFG.source,
    delivery_day: msg.delivery_day,
    windows:{
      primary:{
        start: winPrimary.start,
        end: winPrimary.end,
        avg: +winPrimary.avg.toFixed(2),
        max: +winPrimary.max.toFixed(2)
      },
      secondary: winSecondary && {
        start: winSecondary.start,
        end: winSecondary.end,
        avg: +winSecondary.avg.toFixed(2),
        max: +winSecondary.max.toFixed(2)
      }
    }
  }
};

const controllerStatusMsg = {
  topic:'controller.status',
  payload:{
    ok:true,
    version: VERSION,
    source: CFG.source,
    delivery_day: msg.delivery_day,
    selected:{
      primary:{
        start: winPrimary.start,
        end: winPrimary.end,
        hours: CFG.windowHoursPrimary,
        avg: +winPrimary.avg.toFixed(2)
      },
      secondary: winSecondary ? {
        start: winSecondary.start,
        end: winSecondary.end,
        hours: CFG.windowHoursSecondary,
        avg: +winSecondary.avg.toFixed(2)
      } : null
    }
  }
};

const chartMsgs = [];
const [y,m,d] = msg.delivery_day.split('-').map(Number);
const base = new Date(y,m-1,d).getTime();

hourly.forEach(h => {
  const ts = base + h.hour * 3600000;
  chartMsgs.push({ topic:'EUR/MWh', payload:h.price, timestamp:ts });
  chartMsgs.push({
    topic:'Primary window',
    payload: h.hour>=winPrimary.start && h.hour<winPrimary.end ? h.price : null,
    timestamp:ts
  });
  chartMsgs.push({
    topic:'Secondary window',
    payload: winSecondary &&
      h.hour>=winSecondary.start && h.hour<winSecondary.end
        ? h.price : null,
    timestamp:ts
  });
});

return [
  victronSchedule1Msg,
  victronSchedule2Msg,
  priceWindows,
  controllerStatusMsg,
  chartMsgs,
  null,
  debug({
    version:VERSION,
    primary: winPrimary,
    secondary: winSecondary
  })
];

/**
 * Tesla Charging Controller
 * v1.1
 *
 * INPUT:
 *  - msg.topic === "price.windows"
 *
 * FLOW CONTEXT:
 *  - tesla_window_mode: "primary" | "secondary"
 *
 * OUTPUTS:
 *  [0] tesla.schedule
 *  [1] tesla.status
 * 
 * Optional Enhancements (v1.1+)
 * - SOC-aware window shortening
 * - Skip if already charging
 * - Prevent double-charge (primary + secondary same day) --DONE v1.1.0
 * - Grid-status gating
 * - Vehicle-present detection
 */

const VERSION = '1.1';

// ------------------------------
// Guard: correct input
// ------------------------------
if (msg.topic !== 'price.windows') {
  return [null, null];
}

const windows = msg.payload?.windows;
if (!windows?.primary) {
  return [
    null,
    {
      topic: 'tesla.status',
      payload: {
        ok: false,
        version: VERSION,
        reason: 'NO_PRIMARY_WINDOW',
        source: msg.payload?.source,
        delivery_day: msg.payload?.delivery_day
      }
    }
  ];
}

// ------------------------------
// Window selection
// ------------------------------
const mode = flow.get('tesla_window_mode') ?? 'primary';

let win = windows.primary;
let usedMode = 'primary';

if (mode === 'secondary') {
  if (windows.secondary) {
    win = windows.secondary;
    usedMode = 'secondary';
  } else {
    usedMode = 'primary_fallback';
  }
}

// ------------------------------
// Helpers
// ------------------------------
function toLocalIso(date) {
  const tz = -date.getTimezoneOffset();
  const s = tz >= 0 ? '+' : '-';
  const p = n => String(Math.abs(n)).padStart(2, '0');
  return date.toISOString().replace('Z', `${s}${p(tz/60)}:${p(tz%60)}`);
}

const desiredSoc = Number(flow.get('desired_soc') ?? 80);

// ------------------------------
// Build schedule times
// ------------------------------
const d = new Date();
const start = new Date(d.getFullYear(), d.getMonth(), d.getDate(), win.start);
const end   = new Date(d.getFullYear(), d.getMonth(), d.getDate(), win.end);

// ------------------------------
// OUTPUT #1 — Tesla schedule
// ------------------------------
const scheduleMsg = {
  topic: 'tesla.schedule',
  payload: {
    controller_version: VERSION,
    window_mode: usedMode,
    command_now: {
      type: 'set_charge_limit',
      charge_limit_percent: desiredSoc
    },
    schedule: {
      start_time_iso: toLocalIso(start),
      end_time_iso: toLocalIso(end)
    }
  }
};

// ------------------------------
// OUTPUT #2 — Tesla status
// ------------------------------
const statusMsg = {
  topic: 'tesla.status',
  payload: {
    ok: true,
    version: VERSION,
    window_mode: usedMode,
    source: msg.payload.source,
    delivery_day: msg.payload.delivery_day,
    selected_window: {
      start: win.start,
      end: win.end,
      duration_h: win.end - win.start,
      avg_price_eur_mwh: win.avg_price_eur_mwh
    }
  }
};

// ------------------------------
return [
  scheduleMsg,
  statusMsg
];

/**
 * ECB EUR/CZK FX parser (Node-RED XML safe)
 * - Handles namespaces
 * - Caches value in flow context
 */

const rootKey = Object.keys(msg.payload || {})[0];
if (!rootKey) {
  node.warn('ECB_FX_NO_ROOT');
  return null;
}

const envelope = msg.payload[rootKey];

// Navigate: Envelope → Cube → Cube(time) → Cube(currency)
const cubesLevel1 = envelope.Cube?.[0]?.Cube?.[0]?.Cube;
if (!Array.isArray(cubesLevel1)) {
  node.warn('ECB_FX_INVALID_XML');
  return null;
}

const czk = cubesLevel1.find(c => c.$?.currency === 'CZK');
if (!czk) {
  node.warn('ECB_FX_CZK_NOT_FOUND');
  return null;
}

const rate = Number(czk.$.rate);
if (!Number.isFinite(rate)) {
  node.warn('ECB_FX_INVALID_RATE');
  return null;
}

flow.set('fx', {
  czk_per_eur: rate,
  date: envelope.Cube?.[0]?.Cube?.[0]?.$?.time,
  source: 'ECB'
});

node.status({
  fill: 'green',
  shape: 'dot',
  text: `EUR/CZK ${rate}`
});

return null;

