  return pts.map(p => ({
    hour: Number(p.position[0]) - 1,
    price: Number(p['price.amount'][0])
  }));
}

function parseOteChart(doc) {
  const lines = doc?.data?.dataLine;
  if (!Array.isArray(lines)) throw 'OTE_NO_DATALINE';

  const line = lines.find(l =>
    l.title === '60min price reference (EUR/MWh)'
  );
  if (!line?.point || line.point.length !== 96)
    throw 'OTE_INVALID_POINTS';

  const out = [];
  for (let h = 0; h < 24; h++) {
    const p = Number(line.point[h * 4].y);
    if (!Number.isFinite(p)) throw 'OTE_PRICE_INVALID';
    out.push({ hour: h, price: p });
  }
  return out;
}

// ======================================================
// WINDOW FINDER
// ======================================================
function findCheapestWindowInRange(hourly, startMin, startMax) {
  let best = null;
  for (let s = startMin; s <= startMax; s++) {
    const e = s + CFG.windowHours;
    if (e > 24) continue;

    const slice = hourly.filter(h => h.hour >= s && h.hour < e);
    if (slice.length !== CFG.windowHours) continue;

    const avg = slice.reduce((a,b)=>a+b.price,0) / slice.length;
    const max = Math.max(...slice.map(h=>h.price));

    if (!best || avg < best.avg)
      best = { start:s, end:e, avg, max };
  }
  return best;
}

// ======================================================
// CACHE
// ======================================================
const CACHE_VERSION = 'v2_6_0';
const sig = CFG.source === 'OTE_CHART' ? 'ote' : 'entsoe';
const cacheKey = `prices_${sig}_${msg.delivery_day}_${CACHE_VERSION}`;

let hourly = flow.get(cacheKey);
if (!hourly) {
  try {
    hourly = CFG.source === 'OTE_CHART'
      ? parseOteChart(msg.payload)
      : parseEntsoeA44(msg.payload);
    flow.set(cacheKey, hourly);
  } catch (e) {
    return buildFallback(e);
  }
}

// ======================================================
// MAIN LOGIC
// ======================================================
const winPrimary = findCheapestWindowInRange(hourly, 0, 23 - CFG.windowHours);
const winSecondary = findCheapestWindowInRange(hourly, 10, 17);

if (!winPrimary) return buildFallback('NO_PRIMARY_WINDOW');
if (winPrimary.avg > CFG.maxAvgPrice)
  return buildFallback('PRICE_TOO_HIGH');

// ======================================================
// OUTPUTS
// ======================================================
const victron1 = {
  topic:'victron.schedule',
  payload:{ action:'set_scheduler', schedule:{
    index: 0,
    enabled:true,
    day:7,
    start_minute: winPrimary.start * 60,
    duration_minute: CFG.windowHours * 60,
    soc_setpoint: CFG.desiredSoc
  }}
};

const victron2 = winSecondary ? {
  topic:'victron.schedule',
  payload:{ action:'set_scheduler', schedule:{
    index: 1,
    enabled:true,
    day:7,
    start_minute: winSecondary.start * 60,
    duration_minute: CFG.windowHours * 60,
    soc_setpoint: CFG.desiredSoc
  }}
} : null;

const priceWindows = {
  topic:'price.windows',
  payload:{
    version: VERSION,
    source: CFG.source,
    delivery_day: msg.delivery_day,
    windows:{
      primary:{
        start: winPrimary.start,
        end: winPrimary.end,
        avg: +winPrimary.avg.toFixed(2),
        max: +winPrimary.max.toFixed(2)
      },
      secondary: winSecondary && {
        start: winSecondary.start,
        end: winSecondary.end,
        avg: +winSecondary.avg.toFixed(2),
        max: +winSecondary.max.toFixed(2)
      }
    }
  }
};

const status = {
  topic:'controller.status',
  payload:{
    ok:true,
    version:VERSION,
    source:CFG.source,
    delivery_day:msg.delivery_day,
    selected:{
      start_hour: winPrimary.start,
      end_hour: winPrimary.end,
      avg_price_eur_mwh: +winPrimary.avg.toFixed(2),
      max_price_eur_mwh: +winPrimary.max.toFixed(2)
    }
  }
};

const chartMsgs = [];
const [y,m,d] = msg.delivery_day.split('-').map(Number);
const base = new Date(y,m-1,d).getTime();

hourly.forEach(h => {
  const ts = base + h.hour * 3600000;
  chartMsgs.push({ topic:'EUR/MWh', payload:h.price, timestamp:ts });
  chartMsgs.push({
    topic:'Primary window',
    payload: h.hour>=winPrimary.start && h.hour<winPrimary.end ? h.price : null,
    timestamp:ts
  });
  chartMsgs.push({
    topic:'Secondary window',
    payload: winSecondary &&
      h.hour>=winSecondary.start && h.hour<winSecondary.end
        ? h.price : null,
    timestamp:ts
  });
});

return [
  victron1,
  victron2,
  priceWindows,
  status,
  chartMsgs,
  null,
  debug({
    version:VERSION,
    primary: winPrimary,
    secondary: winSecondary
  })
];

// Save secondary window hours
flow.set('window_hours_secondary', Number(msg.payload));
return msg;

/**
 * Tesla Charging Controller
 * v1.0.0
 *
 * INPUT:
 *   topic: price.windows
 *
 * OUTPUT 1:
 *   tesla.schedule
 *
 * OUTPUT 2:
 *   tesla.status
 * 
 * Optional Enhancements (v1.1+)
 * - SOC-aware window shortening
 * - Skip if already charging
 * - Prevent double-charge (primary + secondary same day)
 * - Grid-status gating
 * - Vehicle-present detection
 */

// ======================================================
// VERSION
// ======================================================
const VERSION = '1.0.0';

// ======================================================
// DEBUG
// ======================================================
const DEBUG = flow.get('debug_tesla') === true;

function debug(msg) {
  if (!DEBUG) return null;
  return { topic: 'DEBUG_TESLA', payload: msg };
}

// ======================================================
// INPUT VALIDATION
// ======================================================
if (msg.topic !== 'price.windows') {
  return null;
}

const pw = msg.payload;

if (!pw?.windows?.primary) {
  return [
    null,
    {
      topic: 'tesla.status',
      payload: {
        ok: false,
        reason: 'NO_PRIMARY_WINDOW',
        version: VERSION
      }
    }
  ];
}

// ======================================================
// CONFIG
// ======================================================
const CFG = {
  desiredSoc: Number(flow.get('tesla_desired_soc') ?? 80),
  preferSecondary: flow.get('tesla_prefer_secondary') === true
};

// ======================================================
// WINDOW SELECTION
// ======================================================
const win =
  CFG.preferSecondary && pw.windows.secondary
    ? pw.windows.secondary
    : pw.windows.primary;

// ======================================================
// TIME CALCULATION
// ======================================================
const [yyyy, mm, dd] = pw.delivery_day.split('-').map(Number);

const start = new Date(yyyy, mm - 1, dd, win.start, 0, 0);
const end   = new Date(yyyy, mm - 1, dd, win.end,   0, 0);

// ======================================================
// TESLA COMMAND
// ======================================================
const teslaScheduleMsg = {
  topic: 'tesla.schedule',
  payload: {
    command_now: {
      type: 'set_charge_limit',
      charge_limit_percent: CFG.desiredSoc
    },
    schedule: {
      start_time_iso: start.toISOString(),
      end_time_iso: end.toISOString()
    }
  }
};

// ======================================================
// STATUS
// ======================================================
const statusMsg = {
  topic: 'tesla.status',
  payload: {
    ok: true,
    version: VERSION,
    delivery_day: pw.delivery_day,
    selected_window: CFG.preferSecondary && pw.windows.secondary
      ? 'secondary'
      : 'primary',
    start_hour: win.start,
    end_hour: win.end,
    target_soc: CFG.desiredSoc
  }
};

// ======================================================
// OUTPUTS
// ======================================================
return [
  teslaScheduleMsg,
  statusMsg,
  debug({
    input: pw,
    selected_window: win
  })
];

// Save Tesla window preference
flow.set('tesla_window_mode', msg.payload); // "primary" | "secondary"
return msg;

// CSV header once per delivery day (Node-RED safe)

const day = msg.delivery_day;
const flagKey = `csv_header_written_${day}`;

if (!flow.get(flagKey)) {
  msg.payload =
    'delivery_day,hour,price_eur_mwh,in_selected_window\n' +
    msg.payload;

  flow.set(flagKey, true);
}

return msg;
